class CloudAPIClient {
    private let baseURL = "https://api.example.com"
    private let httpClient = HTTPClient.shared
    
    func getDevices(completion: @escaping (Result<[Device], Error>) -> Void) {
        let endpoint = "\(baseURL)/devices"
        httpClient.requestJSON(urlString: endpoint, responseType: DevicesResponse.self) { result in
            switch result {
            case .success(let response):
                completion(.success(response.devices))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func updateDevice(deviceId: String, status: DeviceStatus, completion: @escaping (Result<Device, Error>) -> Void) {
        let endpoint = "\(baseURL)/devices/\(deviceId)"
        let body = UpdateDeviceRequest(status: status)
        
        httpClient.uploadJSON(urlString: endpoint, method: .PUT, body: body) { result in
            switch result {
            case .success((let data, _)):
                do {
                    let device = try JSONDecoder().decode(Device.self, from: data)
                    completion(.success(device))
                } catch {
                    completion(.failure(error))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<AuthToken, Error>) -> Void) {
        let endpoint = "\(baseURL)/auth/login"
        let body = AuthRequest(username: username, password: password)
        
        httpClient.uploadJSON(urlString: endpoint, method: .POST, body: body) { result in
            switch result {
            case .success((let data, _)):
                do {
                    let token = try JSONDecoder().decode(AuthToken.self, from: data)
                    completion(.success(token))
                } catch {
                    completion(.failure(error))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
}

class IoTDeviceClient {
    private let httpClient = HTTPClient.shared
    
    func getDeviceStatus(ipAddress: String, completion: @escaping (Result<IoTDeviceStatus, Error>) -> Void) {
        let endpoint = "http://\(ipAddress)/status"
        httpClient.requestJSON(urlString: endpoint, responseType: IoTDeviceStatus.self, completion: completion)
    }
    
    func sendCommand(ipAddress: String, command: IoTCommand, completion: @escaping (Result<IoTCommandResponse, Error>) -> Void) {
        let endpoint = "http://\(ipAddress)/command"
        
        httpClient.uploadJSON(urlString: endpoint, method: .POST, body: command) { result in
            switch result {
            case .success((let data, _)):
                do {
                    let response = try JSONDecoder().decode(IoTCommandResponse.self, from: data)
                    completion(.success(response))
                } catch {
                    completion(.failure(error))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func updateSettings(ipAddress: String, settings: IoTSettings, completion: @escaping (Result<Bool, Error>) -> Void) {
        let endpoint = "http://\(ipAddress)/settings"
        
        httpClient.uploadJSON(urlString: endpoint, method: .PUT, body: settings) { result in
            switch result {
            case .success:
                completion(.success(true))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func discoverDevices(subnet: String = "192.168.1", completion: @escaping ([String]) -> Void) {
        var discoveredDevices: [String] = []
        let dispatchGroup = DispatchGroup()
        let queue = DispatchQueue(label: "com.iotclient.discovery", attributes: .concurrent)
        let lock = NSLock()
        
        for i in 1...254 {
            dispatchGroup.enter()
            queue.async {
                let ipAddress = "\(subnet).\(i)"
                self.getDeviceStatus(ipAddress: ipAddress) { result in
                    if case .success = result {
                        lock.lock()
                        discoveredDevices.append(ipAddress)
                        lock.unlock()
                    }
                    dispatchGroup.leave()
                }
            }
        }
        
        dispatchGroup.notify(queue: .main) {
            completion(discoveredDevices)
        }
    }
}

